import{bV as o,aL as t,u as e,G as s}from"./chunks/framework.BfzMay2U.js";const g=JSON.parse('{"title":"Claude Desktop 第三方 Provider 配置指南","description":"详细讲解如何在 Claude Desktop 中配置自定义第三方 API Provider，包括 macOS 和 Windows 双平台的完整操作流程。","frontmatter":{"title":"Claude Desktop 第三方 Provider 配置指南","description":"详细讲解如何在 Claude Desktop 中配置自定义第三方 API Provider，包括 macOS 和 Windows 双平台的完整操作流程。","date":"2026-05-09T21:22:02.000Z","categories":["ClaudeCode"],"tags":["CC"],"permalink":"/ai/tools/ccdesktop"},"headers":[],"relativePath":"ai/tools/claude-desktop.md","filePath":"ai/tools/claude-desktop.md"}'),i={name:"ai/tools/claude-desktop.md"};function l(r,a,n,d,p,c){return t(),e("div",null,[...a[0]||(a[0]=[s('<h1 id="claude-desktop-第三方-provider-配置指南" tabindex="-1">Claude Desktop 第三方 Provider 配置指南 <a class="header-anchor" href="#claude-desktop-第三方-provider-配置指南" aria-label="Permalink to &quot;Claude Desktop 第三方 Provider 配置指南&quot;">​</a></h1><p>本教程将指导你如何在 Claude Desktop 客户端中配置第三方 API Provider，使其通过自定义网关连接到不同的 AI 服务（如 DragonCode、Kimi 等）。</p><h2 id="前置准备" tabindex="-1">前置准备 <a class="header-anchor" href="#前置准备" aria-label="Permalink to &quot;前置准备&quot;">​</a></h2><p>在开始配置之前，请确保：</p><ol><li>已下载并安装 Claude Desktop 客户端</li><li>拥有第三方服务的 API Key</li><li>了解该服务的 Gateway 地址（Base URL）</li></ol><h3 id="下载-claude-desktop" tabindex="-1">下载 Claude Desktop <a class="header-anchor" href="#下载-claude-desktop" aria-label="Permalink to &quot;下载 Claude Desktop&quot;">​</a></h3><p>访问官方下载页面获取最新版本：</p><p><a href="https://code.claude.com/docs/en/desktop-quickstart" target="_blank" rel="noreferrer">Claude Desktop 下载</a></p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423195403206.png" alt="Claude Desktop 下载页面" loading="lazy"></p><h2 id="macos-配置流程" tabindex="-1">macOS 配置流程 <a class="header-anchor" href="#macos-配置流程" aria-label="Permalink to &quot;macOS 配置流程&quot;">​</a></h2><h3 id="第一步-启用开发者模式" tabindex="-1">第一步：启用开发者模式 <a class="header-anchor" href="#第一步-启用开发者模式" aria-label="Permalink to &quot;第一步：启用开发者模式&quot;">​</a></h3><ol><li><p>打开 Claude Desktop 客户端</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423195504200.png" alt="Claude Desktop 主界面" loading="lazy"></p></li><li><p>点击顶部菜单栏的 <strong>Help（帮助）</strong>，依次选择 <strong>Troubleshooting</strong> → <strong>Enable Developer Mode</strong></p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423195705084.png" alt="启用开发者模式" loading="lazy"></p></li><li><p>在确认对话框中点击 <strong>Enable</strong>，应用将自动重启</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423195751066.png" alt="确认启用开发者模式" loading="lazy"></p></li></ol><h3 id="第二步-配置第三方接口" tabindex="-1">第二步：配置第三方接口 <a class="header-anchor" href="#第二步-配置第三方接口" aria-label="Permalink to &quot;第二步：配置第三方接口&quot;">​</a></h3><ol><li><p>重启后进入欢迎界面，<strong>先不要登录</strong>。保持客户端处于选中状态，此时顶部菜单栏会出现 <strong>Developer</strong> 选项</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423200035068.png" alt="Developer 菜单" loading="lazy"></p></li><li><p>点击 <strong>Developer</strong> → <strong>Configure Provider</strong>，打开配置面板</p></li><li><p>填写第三方接口信息。以 DragonCode 为例：</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423200226091.png" alt="配置第三方接口" loading="lazy"></p><table tabindex="0"><thead><tr><th>配置项</th><th>值</th></tr></thead><tbody><tr><td><strong>Gateway base URL</strong></td><td><code>https://dragoncode.codes</code></td></tr><tr><td><strong>Gateway API key</strong></td><td>你的 DragonCode API Key</td></tr></tbody></table></li><li><p>点击右下角的 <strong>Apply locally</strong></p></li><li><p>在弹出的确认框中选择 <strong>Relaunch now</strong> 重启应用</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423200724818.png" alt="重启确认" loading="lazy"></p></li><li><p>重启后点击 <strong>Continue with gateway</strong>，即可进入主界面</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423200842725.png" alt="Continue with gateway" loading="lazy"></p></li></ol><h3 id="界面说明" tabindex="-1">界面说明 <a class="header-anchor" href="#界面说明" aria-label="Permalink to &quot;界面说明&quot;">​</a></h3><p>进入主界面后，可以使用以下快捷键切换视图：</p><table tabindex="0"><thead><tr><th>快捷键</th><th>功能</th></tr></thead><tbody><tr><td><code>Command + 1</code></td><td>Cowork 界面（默认）</td></tr><tr><td><code>Command + 2</code></td><td>编码界面</td></tr></tbody></table><h3 id="功能验证" tabindex="-1">功能验证 <a class="header-anchor" href="#功能验证" aria-label="Permalink to &quot;功能验证&quot;">​</a></h3><p>配置完成后，可以通过简单对话验证连接是否成功。例如询问当前使用的模型：</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423201548407.png" alt="验证模型连接" loading="lazy"></p><h3 id="插件与技能说明" tabindex="-1">插件与技能说明 <a class="header-anchor" href="#插件与技能说明" aria-label="Permalink to &quot;插件与技能说明&quot;">​</a></h3><p>如果你已在 Claude Code CLI 中配置并启用了插件或技能，Desktop 端会自动同步这些配置。你也可以手动在 Desktop 端上传技能文件：</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423201918419.png" alt="插件与技能同步" loading="lazy"></p><h3 id="高级配置" tabindex="-1">高级配置 <a class="header-anchor" href="#高级配置" aria-label="Permalink to &quot;高级配置&quot;">​</a></h3><h4 id="配置最高权限" tabindex="-1">配置最高权限 <a class="header-anchor" href="#配置最高权限" aria-label="Permalink to &quot;配置最高权限&quot;">​</a></h4><p>默认情况下，Claude Desktop 执行敏感操作时会弹出确认框。如需关闭确认提示，可设置最高权限：</p><ol><li><p>点击左下角的 <strong>Cowork 3P | Gateway</strong> 状态区域，或按 <code>Command + ,</code> 打开设置</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423202005781.png" alt="打开设置" loading="lazy"></p></li><li><p>在设置面板中调整权限级别</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423202235722.png" alt="权限设置入口" loading="lazy"></p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423202733059.png" alt="权限配置详情" loading="lazy"></p></li></ol><h4 id="保持电脑活跃" tabindex="-1">保持电脑活跃 <a class="header-anchor" href="#保持电脑活跃" aria-label="Permalink to &quot;保持电脑活跃&quot;">​</a></h4><p>执行长时间任务时，建议开启 <strong>Keep computer awake</strong> 功能，防止电脑进入休眠状态导致任务中断：</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423202511953.png" alt="Keep computer awake" loading="lazy"></p><blockquote><p><strong>注意</strong>：此功能可防止电脑进入待机状态，显示屏仍可自动关闭。但<strong>合上笔记本电脑盖子仍会使设备进入睡眠状态</strong>。</p></blockquote><h3 id="配置多个-provider" tabindex="-1">配置多个 Provider <a class="header-anchor" href="#配置多个-provider" aria-label="Permalink to &quot;配置多个 Provider&quot;">​</a></h3><p>Claude Desktop 支持配置多个第三方接口，方便在不同服务间切换：</p><ol><li><p>重复启用开发者模式的步骤</p></li><li><p>进入 <strong>Developer</strong> → <strong>Configure Provider</strong></p></li><li><p>点击右上角的下拉菜单（显示当前配置名称，如 <code>default</code>）</p></li><li><p>选择 <strong>New configuration</strong> 创建新配置</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423203331381.png" alt="新建配置" loading="lazy"></p></li><li><p>填写新的 Gateway 地址和 API Key（如 Kimi 的配置信息）</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423203535749.png" alt="配置 Kimi" loading="lazy"></p></li><li><p>应用并重启后，可在已配置的 Provider 间自由切换</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423203608823.png" alt="切换 Provider" loading="lazy"></p></li></ol><h2 id="windows-配置流程" tabindex="-1">Windows 配置流程 <a class="header-anchor" href="#windows-配置流程" aria-label="Permalink to &quot;Windows 配置流程&quot;">​</a></h2><p>Windows 端的配置逻辑与 macOS 基本一致，仅开发者模式的入口方式不同：</p><h3 id="启用开发者模式" tabindex="-1">启用开发者模式 <a class="header-anchor" href="#启用开发者模式" aria-label="Permalink to &quot;启用开发者模式&quot;">​</a></h3><ol><li><p>打开 Claude Desktop，进入欢迎界面的邮箱输入页面</p></li><li><p>按下 <code>Tab</code> 键切换焦点，直到左上角的菜单图标被选中</p></li><li><p>按 <code>Enter</code> 键打开菜单</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/1e3b6e4fdc12d7e76d9b0a7e6205a633a6070ca4.png" alt="Windows 菜单入口" loading="lazy"></p></li><li><p>选择 <strong>Developer</strong> → <strong>Configure third-party interface</strong></p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/018a18e47414f8267efc2f166471d9a00744c93d_2_513x500.png" alt="Windows Developer 菜单" loading="lazy"></p></li></ol><h3 id="配置接口信息" tabindex="-1">配置接口信息 <a class="header-anchor" href="#配置接口信息" aria-label="Permalink to &quot;配置接口信息&quot;">​</a></h3><p>填写 Gateway 地址和 API Key，点击 <strong>Apply locally</strong> 后重启生效：</p><p><img src="https://virusoss.oss-cn-shanghai.aliyuncs.com/image-20260423204249997.png" alt="Windows 配置表单" loading="lazy"></p><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><table tabindex="0"><thead><tr><th>问题</th><th>解决方案</th></tr></thead><tbody><tr><td>配置后无法连接</td><td>检查 Gateway URL 是否以 <code>https://</code> 开头，API Key 是否有效</td></tr><tr><td>切换 Provider 后失效</td><td>确保点击了 <strong>Apply locally</strong> 并重启应用</td></tr><tr><td>权限不足无法执行命令</td><td>在设置中将权限级别调整为最高</td></tr></tbody></table><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li><a href="https://code.claude.com/docs/en/desktop-quickstart" target="_blank" rel="noreferrer">Claude Desktop 官方文档</a></li><li><a href="/docs/backend/ai/claude-code.html">Claude Code CLI 配置指南</a></li></ul>',45)])])}const u=o(i,[["render",l]]);export{g as __pageData,u as default};
